// Initial scaffold. The executor must populate the page with the device's
// platform and operating system using @capacitor/device.
const app = document.getElementById("app");
if (app) {
  const note = document.createElement("p");
  note.textContent = "Replace me with a Device.getInfo() integration.";
  app.appendChild(note);
}

import type { CapacitorConfig } from '@capacitor/cli';

const config: CapacitorConfig = {
  appId: 'com.example.devicedemo',
  appName: 'Device Demo',
  webDir: 'dist'
};

export default config;

